import React, { useState } from 'react';
import { 
  SPORTS_OPTIONS, 
  EQUIPMENT_OPTIONS, 
  TIME_SLOTS, 
  WEEKDAYS 
} from '../constants';
import { TrainingRequest, User } from '../types';

interface TrainerFormProps {
  user: User;
  onSubmit: (data: TrainingRequest) => void;
}

const TrainerForm: React.FC<TrainerFormProps> = ({ user, onSubmit }) => {
  const [selectedSports, setSelectedSports] = useState<string[]>([]);
  const [selectedEquipment, setSelectedEquipment] = useState<string[]>([]);
  const [selectedTimes, setSelectedTimes] = useState<string[]>([]);
  const [selectedDays, setSelectedDays] = useState<string[]>([]);
  const [budget, setBudget] = useState(2500);
  const [email, setEmail] = useState(user.email);

  const toggleItem = (list: string[], setList: React.Dispatch<React.SetStateAction<string[]>>, item: string) => {
    if (list.includes(item)) {
      setList(list.filter(i => i !== item));
    } else {
      setList([...list, item]);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const request: TrainingRequest = {
      id: Math.random().toString(36).substring(7),
      userEmail: email,
      sports: selectedSports,
      equipment: selectedEquipment,
      timeSlots: selectedTimes,
      days: selectedDays,
      budget,
      submittedAt: new Date().toISOString(),
    };
    onSubmit(request);
  };

  return (
    <div className="max-w-4xl mx-auto px-4 py-16">
      <div className="text-center mb-16">
        <h2 className="text-4xl font-bold font-poppins mb-4">Let's Find Your Coach</h2>
        <p className="text-xl text-gray-500">Take a minute to tell us what you're looking for.</p>
      </div>

      <form onSubmit={handleSubmit} className="space-y-12">
        {/* Sports Selection */}
        <div className="bg-white p-8 rounded-3xl shadow-sm border border-gray-100">
          <h3 className="text-xl font-bold mb-6 flex items-center">
            <span className="bg-blue-100 text-blue-600 w-8 h-8 rounded-full flex items-center justify-center mr-3 text-sm">1</span>
            What sports do you want to learn?
          </h3>
          <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-5 gap-4">
            {SPORTS_OPTIONS.map((sport) => (
              <button
                key={sport.label}
                type="button"
                onClick={() => toggleItem(selectedSports, setSelectedSports, sport.label)}
                className={`p-4 rounded-2xl flex flex-col items-center justify-center transition-all border-2 ${
                  selectedSports.includes(sport.label)
                    ? 'border-blue-500 bg-blue-50'
                    : 'border-gray-100 bg-gray-50 hover:border-gray-200'
                }`}
              >
                <span className="text-3xl mb-2">{sport.icon}</span>
                <span className="text-sm font-semibold">{sport.label}</span>
              </button>
            ))}
          </div>
        </div>

        {/* Equipment Selection */}
        <div className="bg-white p-8 rounded-3xl shadow-sm border border-gray-100">
          <h3 className="text-xl font-bold mb-6 flex items-center">
            <span className="bg-purple-100 text-purple-600 w-8 h-8 rounded-full flex items-center justify-center mr-3 text-sm">2</span>
            What equipment do you have available?
          </h3>
          <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-4">
            {EQUIPMENT_OPTIONS.map((item) => (
              <button
                key={item.label}
                type="button"
                onClick={() => toggleItem(selectedEquipment, setSelectedEquipment, item.label)}
                className={`p-4 rounded-2xl flex flex-col items-center justify-center transition-all border-2 ${
                  selectedEquipment.includes(item.label)
                    ? 'border-purple-500 bg-purple-50'
                    : 'border-gray-100 bg-gray-50 hover:border-gray-200'
                }`}
              >
                <span className="text-2xl mb-2">{item.icon}</span>
                <span className="text-sm font-semibold text-center leading-tight">{item.label}</span>
              </button>
            ))}
          </div>
        </div>

        {/* Preferred Training Time */}
        <div className="bg-white p-8 rounded-3xl shadow-sm border border-gray-100">
          <h3 className="text-xl font-bold mb-6 flex items-center">
            <span className="bg-green-100 text-green-600 w-8 h-8 rounded-full flex items-center justify-center mr-3 text-sm">3</span>
            Preferred training time slots
