            />
            <div className="flex justify-between mt-6 items-end">
              <span className="text-gray-400 font-medium text-sm">₹500</span>
              <div className="text-center">
                <div className="text-4xl font-extrabold text-rose-600 font-poppins">₹{budget.toLocaleString()}</div>
                <div className="text-xs text-gray-400 font-bold uppercase tracking-widest mt-1">Per Month</div>
              </div>
              <span className="text-gray-400 font-medium text-sm">₹15,000+</span>
            </div>
          </div>
        </div>

        {/* Email & Final CTA */}
        <div className="bg-gray-900 text-white p-10 rounded-3xl shadow-2xl relative overflow-hidden">
          <div className="relative z-10 flex flex-col md:flex-row items-center gap-8">
            <div className="flex-1">
              <h3 className="text-2xl font-bold mb-2">Almost there!</h3>
              <p className="text-gray-400 mb-6">Confirm your email to receive trainer profiles.</p>
              <input
                type="email"
