                className="w-full px-6 py-4 rounded-xl bg-gray-800 border border-gray-700 text-white placeholder-gray-500 focus:border-blue-500 outline-none transition-all mb-2"
                placeholder="your.email@example.com"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
              />
              <p className="text-xs text-gray-500 italic">“We'll email you once trainers confirm availability.”</p>
            </div>
            <div className="w-full md:w-auto">
              <button
                type="submit"
                className="w-full md:w-auto px-12 py-6 rounded-2xl bg-gradient-to-r from-blue-500 via-purple-500 to-green-500 text-white text-xl font-bold shadow-xl hover:scale-105 transition-all active:scale-95 whitespace-nowrap"
              >
                Find Me a Trainer 🔥
              </button>
            </div>
          </div>
          {/* Subtle background decoration */}
          <div className="absolute top-0 right-0 w-64 h-64 bg-blue-600/10 rounded-full -mr-32 -mt-32 blur-3xl"></div>
          <div className="absolute bottom-0 left-0 w-64 h-64 bg-purple-600/10 rounded-full -ml-32 -mb-32 blur-3xl"></div>
        </div>
      </form>
    </div>
  );
};

export default TrainerForm;

