 * that uses SendGrid, AWS SES, or NodeMailer to send real emails.
 * Here we simulate the functionality as requested.
 */

export const sendSubmissionEmail = async (request: TrainingRequest) => {
  console.log(`%c[EMAIL SERVICE] Sending submission data to: ${ADMIN_EMAIL}`, "color: blue; font-weight: bold;");
  console.log("Submission Payload:", request);

  // Simulation: We "build" the email content using Gemini to show its capability
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are an automated notification system for TrainerBuddy. 
      Generate a professional email body for the site owner (${ADMIN_EMAIL}) notifying them of a new trainer request.

      User Email: ${request.userEmail}
      Sports: ${request.sports.join(', ')}
      Equipment: ${request.equipment.join(', ')}
      Preferred Slots: ${request.timeSlots.join(', ')}
      Days: ${request.days.join(', ')}
      Budget: ₹${request.budget}

      Keep it structured and professional.`,
    });

    console.log("%c[GEMINI GENERATED EMAIL CONTENT]:", "color: green; font-weight: bold;");
    console.log(response.text);
    return true;
  } catch (error) {
    console.error("Failed to generate summary with AI, fallback to standard log:", error);
    return true; // Still return true for simulation
  }
};

