import React, { useState, useEffect } from 'react';
import { View, User, TrainingRequest } from './types';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import Auth from './components/Auth';
import TrainerForm from './components/TrainerForm';
import Confirmation from './components/Confirmation';
import Dashboard from './components/Dashboard';
import { sendSubmissionEmail, sendBuildCompletionEmail } from './services/emailService';
import { saveSubmission } from './services/storageService';

const App: React.FC = () => {
  const [view, setView] = useState<View>(View.HOME);
  const [user, setUser] = useState<User | null>(null);

  useEffect(() => {
    // Check for hash-based routing manually for simpler single-file implementation
    const handleHashChange = () => {
      const hash = window.location.hash.replace('#/', '');
      if (hash === 'admin-secret-dashboard') {
        setView(View.ADMIN);
      } else if (!hash) {
        setView(View.HOME);
      }
    };

    window.addEventListener('hashchange', handleHashChange);
    handleHashChange();

    // Trigger completion email once on load (Simulated)
    sendBuildCompletionEmail();

    return () => window.removeEventListener('hashchange', handleHashChange);
  }, []);

  const handleLogin = (u: User) => {
    setUser(u);
    setView(View.FORM);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleLogout = () => {
    setUser(null);
    setView(View.HOME);
    window.location.hash = '';
  };

  const handleStart = () => {
    if (user?.isLoggedIn) {
      setView(View.FORM);
    } else {
      setView(View.AUTH);
    }
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleFormSubmit = async (data: TrainingRequest) => {
    // 1. Save locally for the secret dashboard
    saveSubmission(data);

    // 2. "Send" email notification
    await sendSubmissionEmail(data);

    // 3. Update UI
    setView(View.SUCCESS);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const navigateTo = (v: View) => {
    setView(v);
    if (v === View.HOME) window.location.hash = '';
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div className="min-h-screen flex flex-col font-sans">
      <Navbar 
        user={user} 
        currentView={view} 
        onNavigate={navigateTo} 
        onLogout={handleLogout} 
      />

      <main className="flex-grow">
        {view === View.HOME && <Hero onStart={handleStart} />}
        {view === View.AUTH && <Auth onLogin={handleLogin} />}
        {view === View.FORM && user && <TrainerForm user={user} onSubmit={handleFormSubmit} />}
        {view === View.SUCCESS && <Confirmation onReset={() => navigateTo(View.HOME)} />}
        {view === View.ADMIN && <Dashboard />}
      </main>

      <footer className="bg-white py-12 border-t border-gray-100">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 flex flex-col md:flex-row justify-between items-center">
          <div className="mb-8 md:mb-0">
            <span className="text-xl font-bold font-poppins">Trainer<span className="text-blue-600">Buddy</span></span>
            <p className="mt-2 text-sm text-gray-400">© 2024 TrainerBuddy. Matching greatness.</p>
          </div>
          <div className="flex space-x-8 text-sm font-semibold text-gray-500">
            <a href="#" className="hover:text-blue-600 transition-colors">About Us</a>
            <a href="#" className="hover:text-blue-600 transition-colors">Find Coaches</a>
            <a href="#" className="hover:text-blue-600 transition-colors">Privacy</a>
            <a href="#" className="hover:text-blue-600 transition-colors">Contact</a>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

