                  <li><a href="mailto:waytown90@Gmail.com" className="hover:text-blue-600 transition-all font-bold text-gray-700">waytown90@Gmail.com</a></li>
                  <li><a href="tel:8779847549" className="hover:text-blue-600 transition-all font-bold text-gray-700">8779847549</a></li>
