export const sendSubmissionEmail = async (request: TrainingRequest) => {
  console.log(`%c[EMAIL SERVICE] Attempting to send real email via EmailJS to: ${ADMIN_EMAIL}`, "color: blue; font-weight: bold;");

  const templateParams = {
    to_email: ADMIN_EMAIL,
