      return true;
    } else {
      const errorData = await response.text();
      console.error("[EMAIL ERROR] EmailJS failed:", errorData);
      return false;
    }
  } catch (error) {
    console.error("[EMAIL ERROR] Failed to fetch EmailJS API:", error);
    return false;
  }
};

