                placeholder="••••••••"
                value={confirmPassword}
                onChange={(e) => setConfirmPassword(e.target.value)}
              />
            </div>
          )}

          <button
            type="submit"
            className="w-full py-4 mt-4 rounded-2xl bg-gray-900 text-white font-black text-lg shadow-xl shadow-gray-200 hover:bg-black hover:scale-[1.02] transition-all active:scale-[0.98]"
          >
            {isLogin ? 'Log In' : 'Sign Up'}
