          </h3>
          <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-5 gap-4">
            {SPORTS_OPTIONS.map((sport) => (
              <button
                key={sport.label}
                type="button"
                onClick={() => toggleItem(selectedSports, setSelectedSports, sport.label)}
