import { GoogleGenAI } from "@google/genai";
import { TrainingRequest } from "../types";

export const getAIRecommendation = async (request: TrainingRequest): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

  if (!process.env.API_KEY) {
    return "Our elite matchmaking engine is analyzing your profile. We'll find a coach that fits your goals and budget perfectly.";
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Act as an elite sports consultant. A user wants to train for ${request.sports.join(", ")}. 
      They have ${request.equipment.join(", ")} available. 
      Their monthly budget is ₹${request.budget.toLocaleString()}. 
      Provide a 2-sentence encouraging insight into what kind of specialist coach they need and why their setup is promising. Keep it premium and professional.`
    });

    return response.text || "Matching you with specialized elite talent...";
  } catch (error) {
    console.error("AI Insight Error:", error);
    return "Your profile is impressive. We're sourcing a coach with the specific expertise needed for your training requirements.";
  }
};

import React, { useEffect, useState } from 'react';
import { TrainingRequest } from '../types';
import { getAIRecommendation } from '../services/aiService';

interface ConfirmationProps {
  onReset: () => void;
  lastRequest: TrainingRequest | null;
}

