import { TrainingRequest, RegisteredUser, User } from '../types';

const SUBMISSIONS_KEY = 'trainerbuddy_submissions';
const USERS_KEY = 'trainerbuddy_registered_users';
const SESSION_KEY = 'trainerbuddy_current_session';

export const saveSubmission = (request: TrainingRequest) => {
  const existing = getSubmissions();
  const updated = [request, ...existing];
  localStorage.setItem(SUBMISSIONS_KEY, JSON.stringify(updated));
};

export const getSubmissions = (): TrainingRequest[] => {
  const data = localStorage.getItem(SUBMISSIONS_KEY);
  return data ? JSON.parse(data) : [];
};

export const clearSubmissions = () => {
  localStorage.removeItem(SUBMISSIONS_KEY);
};

export const registerUser = (user: RegisteredUser) => {
  const users = getRegisteredUsers();
  if (users.find(u => u.email.toLowerCase() === user.email.toLowerCase())) {
    throw new Error('User already exists');
  }
  localStorage.setItem(USERS_KEY, JSON.stringify([...users, user]));
};

export const getRegisteredUsers = (): RegisteredUser[] => {
  const data = localStorage.getItem(USERS_KEY);
  return data ? JSON.parse(data) : [];
};

export const findUser = (email: string): RegisteredUser | undefined => {
  return getRegisteredUsers().find(u => u.email.toLowerCase() === email.toLowerCase());
};

export const saveUserSession = (user: User) => {
  localStorage.setItem(SESSION_KEY, JSON.stringify(user));
};

export const getUserSession = (): User | null => {
  const data = localStorage.getItem(SESSION_KEY);
  return data ? JSON.parse(data) : null;
};

export const clearUserSession = () => {
  localStorage.removeItem(SESSION_KEY);
};

import React, { useState, useEffect } from 'react';
import { View, User, TrainingRequest } from './types';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import Auth from './components/Auth';
import TrainerForm from './components/TrainerForm';
import Confirmation from './components/Confirmation';
import Dashboard from './components/Dashboard';
import { sendSubmissionEmail, sendBuildCompletionEmail } from './services/emailService';
import { saveSubmission, getUserSession, saveUserSession, clearUserSession } from './services/storageService';

const App: React.FC = () => {
  const [view, setView] = useState<View>(View.HOME);
  const [user, setUser] = useState<User | null>(null);
  const [lastRequest, setLastRequest] = useState<TrainingRequest | null>(null);

  // Restore session on mount
  useEffect(() => {
    const savedUser = getUserSession();
    if (savedUser) {
      setUser(savedUser);
      // If they were on admin dashboard, keep them there if still admin
      if (savedUser.isAdmin && window.location.hash === '#/admin-secret-dashboard') {
        setView(View.ADMIN);
      }
    }
  }, []);

  useEffect(() => {
    const handleHashChange = () => {
      const hash = window.location.hash.replace('#/', '');
      if (hash === 'admin-secret-dashboard') {
        if (user?.isAdmin) {
          setView(View.ADMIN);
        } else {
          window.location.hash = '';
          setView(user?.isLoggedIn ? View.FORM : View.HOME);
        }
      } else if (!hash && view !== View.SUCCESS && view !== View.AUTH && view !== View.FORM) {
        setView(View.HOME);
      }
    };

    window.addEventListener('hashchange', handleHashChange);
    handleHashChange();
    sendBuildCompletionEmail();
    return () => window.removeEventListener('hashchange', handleHashChange);
  }, [user, view]);

  const handleLogin = (u: User) => {
    setUser(u);
    saveUserSession(u); // Persist session
    if (u.isAdmin) {
      window.location.hash = '#/admin-secret-dashboard';
      setView(View.ADMIN);
    } else {
      setView(View.FORM);
    }
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleLogout = () => {
    setUser(null);
    clearUserSession(); // Clear session
    setView(View.HOME);
    window.location.hash = '';
  };

  const handleStart = () => {
    if (user?.isLoggedIn) {
      setView(user.isAdmin ? View.ADMIN : View.FORM);
    } else {
      setView(View.AUTH);
    }
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleFormSubmit = async (data: TrainingRequest) => {
    setLastRequest(data);
    saveSubmission(data);
    await sendSubmissionEmail(data);
    setView(View.SUCCESS);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const navigateTo = (v: View) => {
    if (v === View.ADMIN && !user?.isAdmin) {
      setView(View.AUTH);
      return;
    }
    setView(v);
    if (v === View.HOME) window.location.hash = '';
    if (v === View.ADMIN) window.location.hash = '#/admin-secret-dashboard';
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div className="min-h-screen flex flex-col font-sans bg-gray-50/50">
      <Navbar 
        user={user} 
        currentView={view} 
        onNavigate={navigateTo} 
        onLogout={handleLogout} 
      />

      <main className="flex-grow">
        {view === View.HOME && <Hero onStart={handleStart} />}
        {view === View.AUTH && <Auth onLogin={handleLogin} />}
        {view === View.FORM && user && <TrainerForm user={user} onSubmit={handleFormSubmit} />}
        {view === View.SUCCESS && <Confirmation onReset={() => navigateTo(View.HOME)} lastRequest={lastRequest} />}
        {view === View.ADMIN && user?.isAdmin && <Dashboard />}
      </main>

      <footer className="bg-white py-16 border-t border-gray-100">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 text-center md:text-left">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center">
            <div className="mb-10 md:mb-0">
              <span className="text-2xl font-black font-poppins tracking-tighter">
