            </div>
            <div>
              <h4 className="font-black text-gray-900 text-xs uppercase tracking-widest mb-4">Contact</h4>
              <a href="mailto:trainerbuddy1@Gmail.com" className="font-bold text-blue-600">trainerbuddy1@Gmail.com</a>
            </div>
          </div>
        </div>
      </footer>
    </div>
  );
};

