import React, { useState } from 'react';
import { User, RegisteredUser } from '../types';
import { ADMIN_EMAIL, ADMIN_PASSWORD } from '../constants';
import { registerUser, findUser } from '../services/storageService';

interface AuthProps {
  onLogin: (user: User) => void;
}

const Auth: React.FC<AuthProps> = ({ onLogin }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [email, setEmail] = useState('');
  const [phone, setPhone] = useState('');
  const [dob, setDob] = useState('');
  const [gender, setGender] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccess('');
    setIsSubmitting(true);

    const normalizedEmail = email.toLowerCase().trim();

    if (isLogin) {
      // Admin check
      if (normalizedEmail === ADMIN_EMAIL.toLowerCase() && password === ADMIN_PASSWORD) {
        onLogin({ 
          email: normalizedEmail, 
          isLoggedIn: true,
          isAdmin: true
        });
        setIsSubmitting(false);
        return;
      }

      const existing = findUser(normalizedEmail);

      if (!existing) {
        setError('Account not found. Please sign up.');
        setIsSubmitting(false);
        return;
      }

      if (existing.password !== password) {
        setError('Invalid password.');
        setIsSubmitting(false);
        return;
      }

      // NOTE: Login email notification removed per user request
      onLogin({ 
        email: normalizedEmail, 
        phone: existing.phone, 
        dob: existing.dob,
        gender: existing.gender,
        password: existing.password,
        isLoggedIn: true,
        isAdmin: false
      });
    } else {
      // Registration logic
      if (!email || !phone || !dob || !gender || !password || !confirmPassword) {
        setError('Please fill all fields.');
        setIsSubmitting(false);
        return;
      }

      if (password !== confirmPassword) {
        setError('Passwords do not match.');
        setIsSubmitting(false);
        return;
      }

      try {
        const newUser: RegisteredUser = { email: normalizedEmail, phone, dob, gender, password };
        registerUser(newUser);

        // NOTE: Signup email notification removed per user request
        setSuccess('Account created!');

        setTimeout(() => {
          onLogin({ 
            email: normalizedEmail, 
            phone, dob, gender, password,
            isLoggedIn: true,
            isAdmin: false
          });
        }, 1000);
      } catch (e: any) {
        setError(e.message || 'Signup failed.');
      } finally {
        setIsSubmitting(false);
      }
    }
  };

  return (
    <div className="min-h-[85vh] flex items-center justify-center px-4 py-12 bg-gray-50">
      <div className="max-w-md w-full glass rounded-[2.5rem] p-10 shadow-2xl relative overflow-hidden">
        <div className="text-center mb-10">
          <h2 className="text-3xl font-black font-poppins mb-2 text-gray-900">
            {isLogin ? 'Welcome Back' : 'Create Account'}
          </h2>
          <p className="text-gray-500 font-medium">
            {isLogin ? 'Login to TrainerBuddy' : 'Join our elite community'}
          </p>
        </div>

        {error && <div className="mb-6 p-4 bg-red-50 text-red-600 text-sm font-bold rounded-xl">{error}</div>}
        {success && <div className="mb-6 p-4 bg-green-50 text-green-600 text-sm font-bold rounded-xl">{success}</div>}

        <form onSubmit={handleSubmit} className="space-y-4">
          <input
            type="email"
            required
            className="w-full px-5 py-4 rounded-2xl border border-gray-100 bg-white/50 focus:bg-white outline-none"
            placeholder="Email Address"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
          />

          {!isLogin && (
            <>
              <div className="grid grid-cols-2 gap-4">
                <input
                  type="tel"
                  required
                  className="w-full px-5 py-4 rounded-2xl border border-gray-100 bg-white/50 outline-none"
                  placeholder="Phone"
                  value={phone}
                  onChange={(e) => setPhone(e.target.value)}
                />
                <input
                  type="date"
                  required
                  className="w-full px-5 py-4 rounded-2xl border border-gray-100 bg-white/50 outline-none"
                  value={dob}
                  onChange={(e) => setDob(e.target.value)}
                />
              </div>
              <select
                required
                className="w-full px-5 py-4 rounded-2xl border border-gray-100 bg-white/50 outline-none"
                value={gender}
                onChange={(e) => setGender(e.target.value)}
              >
                <option value="" disabled>Select Gender</option>
                <option value="Male">Male</option>
                <option value="Female">Female</option>
                <option value="Other">Other</option>
              </select>
            </>
          )}

          <input
            type="password"
            required
            className="w-full px-5 py-4 rounded-2xl border border-gray-100 bg-white/50 outline-none"
            placeholder="Password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
          />

          {!isLogin && (
            <input
              type="password"
              required
              className="w-full px-5 py-4 rounded-2xl border border-gray-100 bg-white/50 outline-none"
              placeholder="Confirm Password"
              value={confirmPassword}
              onChange={(e) => setConfirmPassword(e.target.value)}
            />
          )}

          <button
            type="submit"
            disabled={isSubmitting}
            className="w-full py-4 mt-4 rounded-2xl bg-gray-900 text-white font-black text-lg shadow-xl hover:bg-black transition-all"
          >
            {isSubmitting ? 'Processing...' : (isLogin ? 'Log In' : 'Sign Up')}
          </button>
        </form>

        <div className="mt-8 text-center">
          <button
            onClick={() => setIsLogin(!isLogin)}
            className="text-sm font-bold text-blue-600 hover:text-blue-700"
          >
            {isLogin ? "Don't have an account? Sign Up" : "Already have an account? Log In"}
          </button>
        </div>
      </div>
    </div>
  );
};

