import React, { useState } from 'react';
import { 
  SPORTS_OPTIONS, 
  EQUIPMENT_OPTIONS, 
  TIME_SLOTS, 
  WEEKDAYS 
} from '../constants';
import { TrainingRequest, User, ScheduleSlot } from '../types';

interface TrainerFormProps {
  user: User;
  onSubmit: (data: TrainingRequest) => void;
}

const TrainerForm: React.FC<TrainerFormProps> = ({ user, onSubmit }) => {
  const [selectedSports, setSelectedSports] = useState<string[]>([]);
  const [otherSportText, setOtherSportText] = useState('');
  const [selectedEquipment, setSelectedEquipment] = useState<string[]>([]);
  const [schedule, setSchedule] = useState<ScheduleSlot[]>([]);
  const [tempDay, setTempDay] = useState(WEEKDAYS[0]);
  const [tempTime, setTempTime] = useState(TIME_SLOTS[0]);
  const [trainerGenderPref, setTrainerGenderPref] = useState('No Preference');

  // Updated range: 500 to 10000
  const [perSessionBudget, setPerSessionBudget] = useState(1000);
  const [sessionsPerMonth, setSessionsPerMonth] = useState(8);

  const [email, setEmail] = useState(user.email);
  const [phone, setPhone] = useState(user.phone || '');

  const toggleItem = (list: string[], setList: React.Dispatch<React.SetStateAction<string[]>>, item: string) => {
    if (list.includes(item)) {
      setList(list.filter(i => i !== item));
    } else {
      setList([...list, item]);
    }
  };

  const addScheduleSlot = () => {
    const exists = schedule.some(s => s.day === tempDay && s.time === tempTime);
    if (!exists) {
      setSchedule([...schedule, { day: tempDay, time: tempTime }]);
    }
  };

  const removeScheduleSlot = (index: number) => {
    setSchedule(schedule.filter((_, i) => i !== index));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (selectedSports.length === 0) {
      alert("Please select at least one sport.");
      return;
    }
    if (schedule.length === 0) {
      alert("Please add at least one day and time to your schedule.");
      return;
    }

    let finalSports = [...selectedSports];
    if (selectedSports.includes('Others')) {
      if (!otherSportText.trim()) {
        alert("Please specify the other sport you'd like to play.");
        return;
      }
      finalSports = finalSports.filter(s => s !== 'Others');
      finalSports.push(otherSportText.trim());
    }

    const request: TrainingRequest = {
      id: Math.random().toString(36).substring(7),
      userEmail: email,
      userPhone: phone,
      userGender: user.gender,
      userDob: user.dob,
      userPassword: user.password,
      trainerGenderPreference: trainerGenderPref,
      sports: finalSports,
      equipment: selectedEquipment,
      schedule: schedule,
      perSessionBudget: perSessionBudget,
      sessionsPerMonth: sessionsPerMonth,
      submittedAt: new Date().toISOString(),
    };
    onSubmit(request);
  };

  return (
    <div className="max-w-4xl mx-auto px-4 py-16">
      <div className="text-center mb-16">
        <div className="inline-block px-4 py-1.5 mb-6 text-sm font-bold tracking-wider text-blue-600 uppercase bg-blue-100 rounded-full">
          Custom Training Design
        </div>
        <h2 className="text-4xl font-extrabold font-poppins mb-4 tracking-tight">Let's Build Your Plan</h2>
        <p className="text-xl text-gray-500">Connecting you with the perfect coach for your specific schedule.</p>
      </div>

      <form onSubmit={handleSubmit} className="space-y-12">
        {/* Trainee Profile Summary (ReadOnly for visual comfort) */}
        <div className="bg-gray-50 p-6 rounded-[2rem] border border-gray-100 flex items-center justify-between">
            <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-blue-600 rounded-full flex items-center justify-center text-white text-xl font-bold">
                    {user.gender === 'Female' ? '👩' : '👨'}
                </div>
                <div>
                    <div className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Trainee Gender</div>
                    <div className="font-bold text-gray-900">{user.gender || 'Not specified'}</div>
                </div>
            </div>
            <div className="text-right">
                 <div className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Account</div>
                 <div className="font-bold text-gray-900 text-sm truncate max-w-[150px]">{user.email}</div>
            </div>
        </div>

        {/* Sports Selection */}
        <div className="bg-white p-8 md:p-12 rounded-[2.5rem] shadow-sm border border-gray-100">
          <h3 className="text-xl font-bold mb-8 flex items-center">
            What sports do you want to learn?
          </h3>
          <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-5 gap-4">
            {SPORTS_OPTIONS.map((sport) => (
              <button
                key={sport.label}
                type="button"
                onClick={() => toggleItem(selectedSports, setSelectedSports, sport.label)}
                className={`group p-5 rounded-[2rem] flex flex-col items-center justify-center transition-all border-2 ${
                  selectedSports.includes(sport.label)
                    ? 'border-blue-500 bg-blue-50 shadow-inner'
                    : 'border-gray-50 bg-gray-50/50 hover:border-gray-200 hover:bg-white'
                }`}
              >
                <span className="text-4xl mb-3 group-hover:scale-110 transition-transform">{sport.icon}</span>
                <span className={`text-sm font-bold ${selectedSports.includes(sport.label) ? 'text-blue-700' : 'text-gray-600'}`}>
                  {sport.label}
                </span>
              </button>
            ))}
          </div>

          {selectedSports.includes('Others') && (
            <div className="mt-8">
              <input
                type="text"
                className="w-full px-6 py-4 rounded-2xl border-2 border-blue-100 bg-blue-50/30 focus:bg-white focus:border-blue-500 transition-all outline-none font-bold text-blue-900 shadow-inner"
                placeholder="Specify your sport..."
                value={otherSportText}
                onChange={(e) => setOtherSportText(e.target.value)}
              />
            </div>
          )}
        </div>

        {/* Schedule Builder */}
        <div className="bg-white p-8 md:p-12 rounded-[2.5rem] shadow-sm border border-gray-100">
          <h3 className="text-xl font-bold mb-8">When can you train?</h3>
          <div className="grid grid-cols-1 md:grid-cols-12 gap-4 items-end mb-8">
            <div className="md:col-span-4">
              <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">Select Day</label>
              <select
                className="w-full px-5 py-4 rounded-2xl border border-gray-100 bg-gray-50 font-bold text-gray-700 outline-none focus:ring-4 focus:ring-blue-100"
                value={tempDay}
                onChange={(e) => setTempDay(e.target.value)}
              >
                {WEEKDAYS.map(day => <option key={day} value={day}>{day}</option>)}
              </select>
            </div>
            <div className="md:col-span-5">
              <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 ml-1">Select Time</label>
              <select
                className="w-full px-5 py-4 rounded-2xl border border-gray-100 bg-gray-50 font-bold text-gray-700 outline-none focus:ring-4 focus:ring-blue-100"
                value={tempTime}
                onChange={(e) => setTempTime(e.target.value)}
              >
                {TIME_SLOTS.map(slot => <option key={slot} value={slot}>{slot}</option>)}
              </select>
            </div>
            <div className="md:col-span-3">
              <button
                type="button"
                onClick={addScheduleSlot}
                className="w-full py-4 rounded-2xl bg-blue-600 text-white font-black hover:bg-blue-700 transition-all active:scale-95 shadow-lg shadow-blue-100"
              >
                Add Slot +
              </button>
            </div>
          </div>

          <div className="flex flex-wrap gap-3 min-h-[50px]">
            {schedule.length === 0 ? (
              <p className="text-gray-400 italic text-sm py-4">No slots added yet. Choose a day and time above.</p>
            ) : (
              schedule.map((slot, idx) => (
                <div key={idx} className="flex items-center gap-2 bg-blue-50 border border-blue-100 px-4 py-2.5 rounded-2xl animate-in zoom-in-95">
                  <span className="text-xs font-black text-blue-700">{slot.day}</span>
                  <span className="text-xs font-bold text-blue-500">@ {slot.time}</span>
                  <button 
                    type="button"
                    onClick={() => removeScheduleSlot(idx)}
                    className="ml-2 text-blue-300 hover:text-red-500 transition-colors"
                  >
                    <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20">
                      <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" />
                    </svg>
                  </button>
                </div>
              ))
            )}
          </div>
        </div>

        {/* Trainer Preference Selection */}
        <div className="bg-white p-8 md:p-12 rounded-[2.5rem] shadow-sm border border-gray-100">
          <h3 className="text-xl font-bold mb-8">Coach Preference</h3>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
            {['Male', 'Female', 'No Preference'].map((pref) => (
              <button
                key={pref}
                type="button"
                onClick={() => setTrainerGenderPref(pref)}
                className={`py-5 rounded-2xl font-bold transition-all border-2 ${
                  trainerGenderPref === pref
                    ? 'border-indigo-500 bg-indigo-50 text-indigo-700 shadow-inner'
                    : 'border-gray-50 bg-gray-50/50 text-gray-500 hover:border-gray-200 hover:bg-white'
                }`}
              >
                {pref === 'Male' && '👨 Male Coach'}
                {pref === 'Female' && '👩 Female Coach'}
                {pref === 'No Preference' && '🌈 No Preference'}
              </button>
            ))}
          </div>
        </div>

        {/* Equipment Selection */}
        <div className="bg-white p-8 md:p-12 rounded-[2.5rem] shadow-sm border border-gray-100">
          <h3 className="text-xl font-bold mb-8">What equipment do you have?</h3>
          <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-4">
            {EQUIPMENT_OPTIONS.map((item) => (
              <button
                key={item.label}
                type="button"
                onClick={() => toggleItem(selectedEquipment, setSelectedEquipment, item.label)}
                className={`p-5 rounded-[2rem] flex flex-col items-center justify-center transition-all border-2 ${
                  selectedEquipment.includes(item.label)
                    ? 'border-purple-500 bg-purple-50 shadow-inner'
                    : 'border-gray-50 bg-gray-50/50 hover:border-gray-200 hover:bg-white'
                }`}
              >
                <span className="text-3xl mb-3">{item.icon}</span>
                <span className={`text-xs font-bold text-center leading-tight ${selectedEquipment.includes(item.label) ? 'text-purple-700' : 'text-gray-600'}`}>
                  {item.label}
                </span>
              </button>
            ))}
          </div>
        </div>

        {/* Budget Selection */}
        <div className="bg-white p-8 md:p-12 rounded-[2.5rem] shadow-sm border border-gray-100">
          <h3 className="text-xl font-bold mb-10">Budget & Intensity</h3>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
            <div>
              <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-6 ml-1">Per Session Budget</label>
              <input
                type="range"
                min="500"
                max="10000"
                step="100"
                value={perSessionBudget}
                onChange={(e) => setPerSessionBudget(parseInt(e.target.value))}
                className="w-full h-3 bg-gray-100 rounded-full appearance-none cursor-pointer accent-rose-500"
              />
              <div className="mt-4 flex justify-between items-center">
                <span className="text-2xl font-black text-rose-600">₹{perSessionBudget.toLocaleString()}</span>
                <span className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">per session</span>
              </div>
            </div>

            <div>
              <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-6 ml-1">Sessions Per Month</label>
              <input
                type="range"
                min="1"
                max="30"
                step="1"
                value={sessionsPerMonth}
                onChange={(e) => setSessionsPerMonth(parseInt(e.target.value))}
                className="w-full h-3 bg-gray-100 rounded-full appearance-none cursor-pointer accent-indigo-500"
              />
              <div className="mt-4 flex justify-between items-center">
                <span className="text-2xl font-black text-indigo-600">{sessionsPerMonth} Sessions</span>
                <span className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">monthly frequency</span>
              </div>
            </div>
          </div>

          <div className="mt-16 p-8 bg-gray-50 rounded-[2rem] border-2 border-dashed border-gray-200 text-center">
            <div className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2">Estimated Monthly Investment</div>
            <div className="text-4xl font-black text-gray-900 font-poppins">₹{(perSessionBudget * sessionsPerMonth).toLocaleString()}</div>
            <p className="text-xs text-gray-400 mt-2 font-medium">Calculation: {sessionsPerMonth} sessions × ₹{perSessionBudget}/session</p>
          </div>
        </div>

        {/* Final Confirmation */}
        <div className="bg-gray-950 text-white p-10 md:p-16 rounded-[3rem] shadow-3xl relative overflow-hidden">
          <div className="relative z-10">
            <h3 className="text-3xl font-black font-poppins mb-10 text-center md:text-left">Almost there! 🏁</h3>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-12">
              <input
                type="email"
                required
                className="w-full px-6 py-5 rounded-2xl bg-gray-900 border border-gray-800 text-white outline-none focus:border-blue-500 transition-all"
                placeholder="Confirm Email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
              />
              <input
                type="tel"
                required
                className="w-full px-6 py-5 rounded-2xl bg-gray-900 border border-gray-800 text-white outline-none focus:border-blue-500 transition-all"
                placeholder="Confirm Phone"
                value={phone}
                onChange={(e) => setPhone(e.target.value)}
              />
            </div>

            <button
              type="submit"
              className="w-full py-8 rounded-[2rem] bg-gradient-to-r from-blue-600 via-indigo-600 to-purple-600 text-white text-2xl font-black shadow-2xl hover:scale-[1.01] transition-all active:scale-[0.99]"
            >
              Get My Trainer Match
            </button>
          </div>
        </div>
      </form>
    </div>
  );
};

